			string strEnum0;
			BlockStyler::PropertyList * strEnum0Props = enum0->GetProperties();
			NXString nxStrEnum0 = strEnum0Props->GetEnumAsString("Value");
			delete strEnum0Props;
			char crstring02[133] = "";
