// 计算矩阵的行列式
double Postprocess::determinant(Matrix3x3& mat)
{
	return mat.data[0][0] * (mat.data[1][1] * mat.data[2][2] - mat.data[2][1] * mat.data[1][2]) -
		mat.data[0][1] * (mat.data[1][0] * mat.data[2][2] - mat.data[1][2] * mat.data[2][0]) +
		mat.data[0][2] * (mat.data[1][0] * mat.data[2][1] - mat.data[1][1] * mat.data[2][0]);
}

//计算矩阵的转置
Postprocess::Matrix3x3 Postprocess::transfer(Matrix3x3& mat)
{
	Matrix3x3 tranMat;
	tranMat.data[0][0] = mat.data[0][0];
	tranMat.data[0][1] = mat.data[1][0];
	tranMat.data[0][2] = mat.data[2][0];
	tranMat.data[1][0] = mat.data[0][1];
	tranMat.data[1][1] = mat.data[1][1];
	tranMat.data[1][2] = mat.data[2][1];
	tranMat.data[2][0] = mat.data[0][2];
	tranMat.data[2][1] = mat.data[1][2];
	tranMat.data[2][2] = mat.data[2][2];

	return tranMat;
}
// 计算矩阵的逆
Postprocess::Matrix3x3 Postprocess::inverse(Matrix3x3& mat)
{
	double det = determinant(mat);
	if (det == 0)
	{
		// 无逆矩阵
		std::cerr << "无法计算逆矩阵，行列式为0。" << std::endl;
		exit(1);
	}

	Matrix3x3 invMat;
	invMat.data[0][0] = (mat.data[1][1] * mat.data[2][2] - mat.data[2][1] * mat.data[1][2]) / det;
	invMat.data[1][0] = (-1)*(mat.data[1][0] * mat.data[2][2] - mat.data[1][2] * mat.data[2][0]) / det;
	invMat.data[2][0] = (mat.data[1][0] * mat.data[2][1] - mat.data[2][0] * mat.data[1][1]) / det;

	invMat.data[0][1] = (-1)*(mat.data[0][1] * mat.data[2][2] - mat.data[0][2] * mat.data[2][1]) / det;
	invMat.data[1][1] = (mat.data[0][0] * mat.data[2][2] - mat.data[0][2] * mat.data[2][0]) / det;
	invMat.data[2][1] = (-1)*(mat.data[0][0] * mat.data[2][1] - mat.data[0][1] * mat.data[2][0]) / det;

	invMat.data[0][2] = (mat.data[0][1] * mat.data[1][2] - mat.data[0][2] * mat.data[1][1]) / det;
	invMat.data[1][2] = (-1)*(mat.data[0][0] * mat.data[1][2] - mat.data[1][0] * mat.data[0][2]) / det;
	invMat.data[2][2] = (mat.data[0][0] * mat.data[1][1] - mat.data[1][0] * mat.data[0][1]) / det;

	return invMat;
}


// 向量叉乘
Postprocess::Vector3 Postprocess::crossProduct(const Vector3& v1, const Vector3& v2)
{
	Vector3 result;
	result.x = v1.y * v2.z - v1.z * v2.y;
	result.y = v1.z * v2.x - v1.x * v2.z;
	result.z = v1.x * v2.y - v1.y * v2.x;
	return result;
}

// 向量点乘
double Postprocess::dotProduct(const Vector3& v1, const Vector3& v2)
{
	return v1.x * v2.x + v1.y * v2.y + v1.z * v2.z;
}

// 标准化向量
Postprocess::Vector3  Postprocess::normalize(const Vector3& v)
{
	double length = std::sqrt(v.x * v.x + v.y * v.y + v.z * v.z);
	Vector3 result = { v.x / length, v.y / length, v.z / length };
	return result;
}

// 计算旋转矩阵和平移向量
void Postprocess::computeTransform(const Vector3& original_pos, const Vector3& original_x, const Vector3& original_y, const Vector3& original_z,
	const Vector3& transformed_pos, const Vector3& transformed_x, const Vector3& transformed_y, const Vector3& transformed_z,
	Matrix3x3& rotation_matrix, Vector3& translation_vector)
{
	// 计算平移向量
	translation_vector.x = transformed_pos.x - original_pos.x;
	translation_vector.y = transformed_pos.y - original_pos.y;
	translation_vector.z = transformed_pos.z - original_pos.z;

	// 计算旋转矩阵
	Vector3 x_axis = normalize(transformed_x);
	Vector3 y_axis = normalize(transformed_y);
	Vector3 z_axis = normalize(transformed_z);

	Vector3 new_x = normalize(crossProduct(y_axis, z_axis));
	Vector3 new_y = normalize(crossProduct(z_axis, x_axis));
	Vector3 new_z = normalize(crossProduct(x_axis, y_axis));

	rotation_matrix.data[0][0] = dotProduct(new_x, original_x);
	rotation_matrix.data[0][1] = dotProduct(new_x, original_y);
	rotation_matrix.data[0][2] = dotProduct(new_x, original_z);

	rotation_matrix.data[1][0] = dotProduct(new_y, original_x);
	rotation_matrix.data[1][1] = dotProduct(new_y, original_y);
	rotation_matrix.data[1][2] = dotProduct(new_y, original_z);

	rotation_matrix.data[2][0] = dotProduct(new_z, original_x);
	rotation_matrix.data[2][1] = dotProduct(new_z, original_y);
	rotation_matrix.data[2][2] = dotProduct(new_z, original_z);
}

// 提取绕 Z 轴的旋转角度
double Postprocess::extractRotationAngleZ(const Matrix3x3& rotationMatrix)
{
	return std::atan2(rotationMatrix.data[1][0], rotationMatrix.data[0][0]);
}

// 提取绕 Y 轴的旋转角度
double Postprocess::extractRotationAngleY(const Matrix3x3& rotationMatrix)
{
	double cos_angle_y = std::sqrt(rotationMatrix.data[2][2] * rotationMatrix.data[2][2] +
		rotationMatrix.data[2][1] * rotationMatrix.data[2][1]);
	return std::atan2(cos_angle_y, rotationMatrix.data[2][0]);
}

// 提取绕 X 轴的旋转角度
double Postprocess::extractRotationAngleX(const Matrix3x3& rotationMatrix)
{
	double cos_angle_x = std::sqrt(rotationMatrix.data[2][2] * rotationMatrix.data[2][2] +
		rotationMatrix.data[2][0] * rotationMatrix.data[2][0]);
	return std::atan2(cos_angle_x, rotationMatrix.data[2][1]);
}

Postprocess::Matrix3x3 Postprocess::multiply(Matrix3x3& A, Matrix3x3& B)
{
	Matrix3x3 result;
	result.data[0][0] = A.data[0][0] * B.data[0][0] + A.data[0][1] * B.data[1][0] + A.data[0][2] * B.data[2][0];
	result.data[0][1] = A.data[0][0] * B.data[0][1] + A.data[0][1] * B.data[1][1] + A.data[0][2] * B.data[2][1];
	result.data[0][2] = A.data[0][0] * B.data[0][2] + A.data[0][1] * B.data[1][2] + A.data[0][2] * B.data[2][2];

	result.data[1][0] = A.data[1][0] * B.data[0][0] + A.data[1][1] * B.data[1][0] + A.data[1][2] * B.data[2][0];
	result.data[1][1] = A.data[1][0] * B.data[0][1] + A.data[1][1] * B.data[1][1] + A.data[1][2] * B.data[2][1];
	result.data[1][2] = A.data[1][0] * B.data[0][2] + A.data[1][1] * B.data[1][2] + A.data[1][2] * B.data[2][2];

	result.data[2][0] = A.data[2][0] * B.data[0][0] + A.data[2][1] * B.data[1][0] + A.data[2][2] * B.data[2][0];
	result.data[2][1] = A.data[2][0] * B.data[0][1] + A.data[2][1] * B.data[1][1] + A.data[2][2] * B.data[2][1];
	result.data[2][2] = A.data[2][0] * B.data[0][2] + A.data[2][1] * B.data[1][2] + A.data[2][2] * B.data[2][2];

	return result;
}
